class Solution {
public:
    int findIntegers(int n) {
        vector<int> fib(31, 0);
        fib[1] = 2;
        fib[2] = 3;
        for (int i = 3; i <= 30; i++) {
            fib[i] = fib[i - 1] + fib[i - 2];
        }
        int res = 0, i = 30;
        while (i >= 0) {
            if ((1 << i) & n) {
                res += fib[i];
                if ((1 << (i - 1)) & n) {
                    return res;
                }
                i--;
            } else {
                i--;
            }
        }
        return res + 1;
    }
};
